%[text] # 컬러 이미지
"양연우"  %[output:9970b99c]
%%
%[text] ## 간단한 컬러 이미지
%[text] - 이미지: mxnx3 RGB triplet pixel이 2차원으로 배열된 3차원 행렬
%[text] - RGB Triplet: 24-bit True color representation, 8bit each x R, G, B
%[text] - 빨간색 이미지 \
clear; % 저장된 변수 값 초기화

h = 100; %높이
w = 200; % 폭
r = 255; % R 성분 최대값

C = zeros(h, w, 3, 'uint8'); 
% x, y, z 3차원: 옛날 프린트 생각 -> 빨간색 위에 파란색, 초록색 덮어씌우 것
C(:,:,1) = r; % 전체 행렬에 빨간색으로 r로 채워라
imshow(C); %[output:1571bf94]
%%
%[text] - 노란색 = 빨간색 + 녹색 , Y = R + G \
clear;
h = 100; % 높이
w = 300; % 폭
C = zeros(h, w, 3, 'uint8');
C(:, 1:200, 1) = 255; % 폭의 1부터 200까지 빨간색 
C(:, 101:300, 2) = 255; % 폭의 101부터 300까지 초록색 
% 101부터 200까지 노란색
imshow(C); %[output:77e275ca]
%%
%[text] ## HTML Color Names
clear;
myColor = [251, 195, 192]; % 파스텔 톤 핑크색의 RGB값

h = 100; % 높이
w = 600; % 폭

C = zeros(h, w, 3, 'uint8');
C(:,:,1) = myColor(1); % R값을 myColor 변수의 인덱스를 통하여 가져오기
C(:,:,2) = myColor(2); % G값을 myColor 변수의 인덱스를 통하여 가져오기
C(:,:,3) = myColor(3); % B값을 myColor 변수의 인덱스를 통하여 가져오기

imshow(C) %[output:50f4d1dd]
%%
%[text] ## 연습문제1: BTS Color
clear;

% 각 색의 RGB 값
MP = [239 63 175]; 
PV = [203 37 209];
DP = [107 38 175];

% 각 색의 폭 영역
mp = [1:200];
pv = [201:400];
dp = [401:600];

h = 100; % 높이
w = 600; % 폭

C = zeros(h, w, 3, 'uint8');

% Magenta/Pink
C(:,mp,1) = MP(1);
C(:,mp,2) = MP(2);
C(:,mp,3) = MP(3);

% Purple/Violet
C(:,pv,1) = PV(1);
C(:,pv,2) = PV(2);
C(:,pv,3) = PV(3);

% Deep Purple
C(:,dp,1) = DP(1);
C(:,dp,2) = DP(2);
C(:,dp,3) = DP(3);

imshow(C) %[output:70a3d812]
%%
%[text] ## 컬러 그라데이션 띠 만들기
%[text] - 컬러 이미지는 세 장의 2차원 이미지를 포개어 만들 수도 있습니다. 이번에는 컬러 그라데이션 띠를 만들기 위해 R, G, B  세장의 2차원 이미지를 만들고 C=cat(3,R,G,B) 명령을 통해 컬러 이미지 C를 생성하겠습니다. \
clear;

h = 100;
w = 20;

r = uint8(250:-10:10); % 빨간색을 벡터로: 250부터 10까지 -10 선명 -> 흐림
b = uint8(10:10:250); % 파란색을 벡터로: 10부터 250까지 +10 흐림 -> 선명
% 그라데이션: 빨강 -> 보라 -> 파랑

K = ones(h, w, 'uint8'); % 100x20
R = kron(r, K); % 100x500 사이즈의 빨간색 정보를 가지고 있는 2차원 행렬
G = 0 * R; % 100x500 사이즈의 0이라는 정보(초록색)를 가지고 있는 2차원 행렬
B = kron(b, K); % 100x500 사이즈의 파란색 정보를 가지고 있는 2차원 행렬

C = cat(3, R, G, B); % R, G, B라는 2차원 행렬들을 3차원 행렬로 묶겠다.

imshow(C); %[output:7c04b2b1]
%%
%[text] ## 컬러 팔레트 만들기
clear;

n = 24; % 색을 24개 만들겠다
C = hsv(n); % MATLAB의 hsv 컬러맵에서 24개의 RGB 색상값을 가져옴 C의 크기는 24 × 3
% C = [r1 g1 b1; r2 g2 b2; ... r24 g24 b24]
figure; % 그래프 창 생성 %[output:5201c3f9]

subplot(3, 1, 1); % 화면을 3행 1열로 나눔 -> 그 중 첫 번째 %[output:5201c3f9]
plot(C(:,1), 'r-o'); % C(:,1) = [r1; r2; ... r24]를 삘간 실선으로 동그라미 표시 연결 %[output:5201c3f9]

subplot(3, 1, 2); %[output:5201c3f9]
plot(C(:,2), 'g-o'); %[output:5201c3f9]

subplot(3, 1, 3); %[output:5201c3f9]
plot(C(:,3), 'b-o'); %[output:5201c3f9]

r = uint8(255 * C(:, 1))'; 
% C(:,1)은 0부터 1 / 우리가 필요한 것은 0~255 이기에 * 255
% 열 벡터를 행 벡터로 바꿔주기 24x1 -> 1x24
g = uint8(255 * C(:, 2))';
b = uint8(255 * C(:, 3))';

h = 100; % 높이
w = 40; % 폭

K = ones(h, w, 'uint8'); % 100x40

R = kron(r, K); % 빨강색의 정보를 가지고 있는 100x960 사이즈 행렬
G = kron(g, K);
B = kron(b, K);

P = cat(3, R, G, B); % 2차원 행렬 RGB를 3차원으로 묶기
figure %[output:06efa867]
imshow(P) %[output:06efa867]
%%
%[text] ## 연습 문제 2: 2차원 컬러 팔레트 만들기
%[text] - 각 타일의 크기는 50x50
%[text] - 위에서 만든 팔레트를 다음과 같이 배치하시오 \
clear;

n = 24;
C = hsv(n); % 24x3

h = 50;
w = 50;

r = uint8(255 * C(:,1))'; % 1x24
g = uint8(255 * C(:,2))'; 
b = uint8(255 * C(:,3))';

R0 = reshape(r, 4, 6); % 4x6
G0 = reshape(g, 4, 6);
B0 = reshape(b, 4, 6);

K = ones(h, w, 'uint8'); % 50x50

R = kron(R0, K); % 200x300
G = kron(G0, K);
B = kron(B0, K);

Q = cat(3, R, G, B);

imshow(Q) %[output:88df73ff]
%%
%[text] ## 랜덤 컬러 타일 만들기
%[text] - randi(imax, m, n): 1 ~ imax 사이의 랜덤 정수로 이루어진 mxn 행렬 \
clear;

h = 20; % 높이
w = 20; % 폭
n = 10; 

K = ones(h, w, 'uint8'); % 20x20 한 칸의 사이즈

r = randi([50 200], n, n, 'uint8'); % 50부터 200까지의 랜덤 정수 10x10 행렬
R = kron(r, K); % 200x200 색 정보 가지고 있는

g = randi([50 200], n, n, 'uint8');
G = kron(g, K);

b = randi([50 200], n, n, 'uint8');
B = kron(b, K);

C = cat(3, R, G, B);
figure %[output:7b33f863]
imshow(C) %[output:7b33f863]
%[text] ## 테두리 만들기
bd = [10 10];
R1 = padarray(R, bd, 0, "both");
G1 = padarray(G, bd, 0, "both");
B1 = padarray(B, bd, 0, "both");
C1 = cat(3,R1,G1,B1); % R, G, B를 3차원으로 묶기 
figure %[output:6f727af7]
imshow(C1) %[output:6f727af7]
%%
%[text] ## 연습 문제 3: 2중 테두리 만들기
clear;

n = 10; % 행, 열 팔레트 개수
h = 20; % 높이
w = 20; % 폭
bd = [10 10]; % 테두리 두께

K = ones(h, w, 'uint8'); % 한 칸에 20x20 사이즈

r = randi([50 200], n, n, 'uint8'); % 50부터 200까지 무작위 정수가 10x10
g = randi([50 200], n, n, 'uint8');
b = randi([50 200], n, n, 'uint8');

R = kron(r, K); % 색상 정보가 포함된 200x200 
G = kron(g, K);
B = kron(b, K);

% 두께 10만큼 하얀색으로 테두리
R1 = padarray(R, bd, 255, 'both'); 
G1 = padarray(G, bd, 255, 'both');
B1 = padarray(B, bd, 255, 'both');

% 두께 10만큼 빨간색으로 테두리
R2 = padarray(R1, bd, 255, 'both');
G2 = padarray(G1, bd, 0, 'both');
B2 = padarray(B1, bd, 0, 'both');

C = cat(3, R2, G2, B2);

imshow(C) %[output:45a29e03]
%%
%[text] ## 부등식을 이용한 컬러 이미지
%[text] - meshgrid()를 이용하여 부등식으로 컬러 이미지 만들기
%[text] - $y=x+100$ 만들기 \
clear;

x = -200:200; % x: -200 ~ 200
y = x + 100; 
plot(x, y, 'LineWidth', 1); % x축에 x / y축에 y 선 너비는 1 %[output:254137cc]
axis equal; %[output:254137cc]
axis square; %[output:254137cc]
grid on; %[output:254137cc]
axis(200*[-1 1 -1 1]); % x축 y축 범위 -200 ~ 200 %[output:254137cc]
%[text] - $y\>x+100$의 영역은 노랑색, 나머지 영역은 보라색으로 설정 \
clear;

h = 400; % 높이
w = 400; % 폭

[X, Y] = meshgrid(-w/2:w/2-1, h/2-1:-1:-h/2); % X: -200 ~ 199 Y: 199 ~ -200

Z = Y -X - 100; % 기울기
M = logical(Z > 0); % 기울기 보다 큰 부분 작은 부분 구분을 위한 마스킹
% logical 없어도 동일 작동

R = ones(h, w, 'uint8') * 255; % 노란색과 보라색 모두 빨간색 필요
% 노란색 
G = R; % 일단 전체 영역에 칠하기
G(~M) = 0; % 기울기 보다 작은 부분은 색상 빼기
% 보라색
B = R; % 일단 전체 영역에 칠하기
B(M) = 0; % 기울기 보다 큰 부분은 색상 빼기

C = cat(3, R, G, B);
imshow(C) %[output:725a0ffb]
%%
%[text] ## 두 영역의 부등식 적용하기
%[text] - 영역 1: $y\>x+100$
%[text] - 영역 2: $y\>-x-100$ \
clear;

h = 400;
w = 400;

[X, Y] = meshgrid(-w/2:w/2-1, h/2-1:-1:-h/2);

Z1 = Y - X - 100;
Z2 = Y + X + 100;
M1 = logical(Z1 > 0);
M2 = logical(Z2 > 0);

R = zeros(h, w, 'uint8'); %400x400에 검은 화면

G = R;
B = R;
R(M1) = 150; % 영역 1에 해당하는 범위 빨간색 150만큼

G(M2) = 200; % 영역 2에 해당하는 범위 초록색 150만큼
B(~M1 & ~M2) = -200; % 영역 1, 2에 해당하지 않는 범위 파란색 -200만큼

C = cat(3, R,G,B);
imshow(C) %[output:3540f55f]
%%
%[text] ## 연습 문제 4: 두 부등식 영역으로 이미지 만들기
%[text] - $y=x+100$
%[text] - $y = x-100$ \
clear;

h = 400; % 높이
w = 400; % 폭

% 영역 색
PP = [251, 195, 193]; % 파스첼 핑크
PB = [118, 210, 219]; % 파스텔 블루
PY = [255, 245, 126]; % 파스텔 옐로우
 
[X, Y] = meshgrid(-w/2:w/2-1, h/2-1:-1:-h/2);

Z1 = Y - X - 100;
Z2 = Y - X + 100;
M1 = logical(Z1 > 0);
M2 = logical(Z2 < 0);
M3 = logical(~M1 & ~M2);

R = zeros(h, w, 'uint8');
G =R;
B =R;

%영역 1
R(M1) = PP(1);
G(M1) = PP(2);
B(M1) = PP(3);
% 영역 2
R(M2) = PB(1);
G(M2) = PB(2);
B(M2) = PB(3);
% 영역 1도 영역 2도 아닌 공간
R(M3) = PY(1);
G(M3) = PY(2);
B(M3) = PY(3);

C = cat(3, R, G, B);
imshow(C) %[output:2aa29f29]
%%
%[text] ## 곡선 적용하기
%[text] - 원 영역: $(x-150)^2+y^2\<150^2$
%[text] - 포물선 영역: $y\<-0.01 .\\times x^2 + 200$ \
clear;

h = 400;
w = 400;

[X, Y] = meshgrid(-w/2:w/2-1, h/2-1:-1:-h/2);

Z1 = (X - 150).^2 + Y.^2;
Z2 = Y + 0.01 * X.^2 - 200;
M1 = logical(Z1 < 150^2);
M2 = logical(Z2 < 0);

R = ones(h, w, 'uint8') * 200; % 전체에 빨간색
G = R; % 전체에 초록색 -> 전체 노란색
B = R * 0;

G(M1) = 50; % 영역 1에 초록색 추가
R(M2) =  80; % 영역 2에 빨간색 추가
B(M1&M2) = 200; % 두 영역의 교집합에 파란색 200 추가

C = cat(3, R, G, B);
imshow(C) %[output:90356645]
%%
%[text] ## 연습 문제 5: 곡선 영역 이미지 만들기
%[text] - $(x-200)^2 + (y-200)^2 = 400^2$
%[text] - $(x-200)^2 + (y+200)^2 = 400^2$
%[text] - $(x+200)^2 + (y-200)^2 = 400^2$
%[text] - $(x+200)^2 + (y+200)^2 = 400^2$ \
clear;

h = 400;
w = 400;

[X, Y] = meshgrid(-w/2:w/2-1, h/2-1:-1:-h/2);

Z1 = (X-200).^2 + (Y-200).^2;
Z2 = (X-200).^2 + (Y+200).^2;
Z3 = (X+200).^2 + (Y-200).^2;
Z4 = (X+200).^2 + (Y+200).^2;

M1 = logical(Z1 > 400^2);
M2 = logical(Z2 > 400^2);
M3 = logical(Z3 > 400^2);
M4 = logical(Z4 > 400^2);

B = zeros(h, w, 'uint8');
R = B * 0;
G = B * 0;

G(M1) = 255;
R(M2) = 255;
R(M3) = 255;
G(M4) = 255;
B(~M1 & ~M2 & ~M3 & ~M4) = 255;

C = cat(3, R, G, B);
imshow(C); %[output:5897466c]

